validation_script:
#!/bin/bash
output=$(ansible all -a 'ssh -V' 2>&1)
if echo "$output" | grep -q 'OpenSSH'; then exit 0; else exit 1; fi

#!/bin/bash
output=$(ansible all -m setup -a 'filter=ansible_distribution' 2>&1)
if echo "$output" | grep -q '"ansible_distribution": "Rocky"'; then exit 0; else exit 1; fi
